"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["27904"],{96478(s){s.exports=JSON.parse('{"tag":{"label":"pacs","permalink":"/sysanalyst-kb.github.io/docs/tags/pacs","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":1,"items":[{"id":"specialization/medtech-pacs","title":"PACS / DICOM \u2014 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0435 \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F","description":"PACS (Picture Archiving and Communication System) \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0434\u043B\u044F \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0441\u043C\u043E\u0442\u0440\u0430 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0445 \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0439 (\u0440\u0435\u043D\u0442\u0433\u0435\u043D, \u041A\u0422, \u041C\u0420\u0422, \u043C\u0430\u043C\u043C\u043E\u0433\u0440\u0430\u0444\u0438\u044F). DICOM \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u0434\u043B\u044F \u043F\u0435\u0440\u0435\u0434\u0430\u0447\u0438 \u0438 \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0439. \u0422\u0438\u043F\u043E\u0432\u043E\u0435 \u0445\u0440\u0430\u043D\u0438\u043B\u0438\u0449\u0435 \u043E\u0431\u043B\u0430\u0441\u0442\u043D\u043E\u0439 \u0431\u043E\u043B\u044C\u043D\u0438\u0446\u044B \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044F PACS \u0441 \u041C\u0418\u0421 (HL7), RIS (\u0440\u0430\u0434\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0418\u0421), \u043C\u043E\u0434\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044F\u043C\u0438 (\u0430\u043F\u043F\u0430\u0440\u0430\u0442\u044B \u041A\u0422/\u041C\u0420\u0422), \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 5+ \u043B\u0435\u0442, DICOM-\u0442\u0435\u0433\u0438 (\u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435 \u0441\u043D\u0438\u043C\u043A\u0430).","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-pacs"}],"unlisted":false}}')}}]);